const express = require('express');
const { MongoClient } = require('mongodb');

const app = express();
app.use(express.json());

// ---------------------------------------------------------------------------
// Whitelist of allowed MongoDB query operators
// ---------------------------------------------------------------------------
const ALLOWED_QUERY_OPERATORS = new Set([
  '$gt', '$gte', '$lt', '$lte', '$eq', '$ne',
  '$in', '$nin',
  '$exists', '$type',
  '$regex', '$options',
  '$all', '$elemMatch', '$size',
  '$and', '$or', '$nor', '$not',
  '$mod',
]);

// Operators that are explicitly DENIED because they allow arbitrary code
// execution or are otherwise dangerous.
const DENIED_OPERATORS = new Set([
  '$where',
  '$accumulator',
  '$function',
  '$expr',       // can be abused in combination with other operators
  '$jsonSchema', // not dangerous per se, but not needed for querying
]);

// ---------------------------------------------------------------------------
// Sanitisation helpers
// ---------------------------------------------------------------------------

/**
 * Recursively sanitise a filter/query object.
 *  - Rejects any key that is in the DENIED_OPERATORS set.
 *  - Rejects any key that starts with '$' but is NOT in the ALLOWED_QUERY_OPERATORS set.
 *  - Rejects any field name that contains a '.' or starts with '$' at the field level
 *    (prevents prototype‑pollution‑style attacks on nested paths).
 *  - Ensures $regex values are strings (prevents RegExp‑DoS via object injection).
 *  - Ensures $in / $nin values are arrays of primitives.
 */
function sanitiseFilter(obj, depth = 0) {
  if (depth > 10) {
    throw new Error('Filter object nested too deeply');
  }

  if (obj === null || obj === undefined) {
    return {};
  }

  if (typeof obj !== 'object' || Array.isArray(obj)) {
    throw new Error('Filter must be a plain object');
  }

  const clean = {};

  for (const key of Object.keys(obj)) {
    const value = obj[key];

    // --- operator keys (start with $) ---
    if (key.startsWith('$')) {
      if (DENIED_OPERATORS.has(key)) {
        throw new Error(`Operator "${key}" is not allowed`);
      }
      if (!ALLOWED_QUERY_OPERATORS.has(key)) {
        throw new Error(`Operator "${key}" is not recognised / allowed`);
      }

      // Special handling per operator
      if (key === '$regex') {
        if (typeof value !== 'string') {
          throw new Error('$regex value must be a string');
        }
        clean[key] = value;
        continue;
      }

      if (key === '$options') {
        if (typeof value !== 'string' || !/^[imxs]{0,4}$/.test(value)) {
          throw new Error('$options value must be a valid regex flag string');
        }
        clean[key] = value;
        continue;
      }

      if (key === '$in' || key === '$nin' || key === '$all') {
        if (!Array.isArray(value)) {
          throw new Error(`${key} value must be an array`);
        }
        // Only allow primitives inside the array
        clean[key] = value.map((item) => {
          if (item !== null && typeof item === 'object') {
            throw new Error(`${key} array elements must be primitives`);
          }
          return item;
        });
        continue;
      }

      if (key === '$mod') {
        if (!Array.isArray(value) || value.length !== 2 ||
            typeof value[0] !== 'number' || typeof value[1] !== 'number') {
          throw new Error('$mod must be an array of two numbers');
        }
        clean[key] = value;
        continue;
      }

      // Logical operators contain arrays of sub‑filters
      if (key === '$and' || key === '$or' || key === '$nor') {
        if (!Array.isArray(value)) {
          throw new Error(`${key} must be an array`);
        }
        clean[key] = value.map((sub) => sanitiseFilter(sub, depth + 1));
        continue;
      }

      if (key === '$not') {
        if (typeof value !== 'object' || value === null || Array.isArray(value)) {
          throw new Error('$not must be an object');
        }
        clean[key] = sanitiseFilter(value, depth + 1);
        continue;
      }

      if (key === '$elemMatch') {
        if (typeof value !== 'object' || value === null || Array.isArray(value)) {
          throw new Error('$elemMatch must be an object');
        }
        clean[key] = sanitiseFilter(value, depth + 1);
        continue;
      }

      // For comparison operators the value should be a primitive or Date string
      if (['$gt', '$gte', '$lt', '$lte', '$eq', '$ne', '$size'].includes(key)) {
        if (value !== null && typeof value === 'object') {
          throw new Error(`${key} value must be a primitive`);
        }
        clean[key] = value;
        continue;
      }

      if (key === '$exists') {
        if (typeof value !== 'boolean') {
          throw new Error('$exists value must be a boolean');
        }
        clean[key] = value;
        continue;
      }

      if (key === '$type') {
        if (typeof value !== 'string' && typeof value !== 'number') {
          throw new Error('$type value must be a string or number');
        }
        clean[key] = value;
        continue;
      }

      // Fallback – allow primitive values only
      if (value !== null && typeof value === 'object') {
        throw new Error(`Unsupported complex value for operator ${key}`);
      }
      clean[key] = value;
      continue;
    }

    // --- field‑level keys ---
    // Reject field names that could be used for injection
    if (key.includes('\0')) {
      throw new Error('Field names must not contain null bytes');
    }

    // Value is a plain primitive → direct equality match
    if (value === null || typeof value !== 'object') {
      clean[key] = value;
      continue;
    }

    // Value is an object → recurse (it should contain operators)
    if (Array.isArray(value)) {
      // Arrays at field level are not standard in a filter; reject
      throw new Error(`Unexpected array value for field "${key}"`);
    }

    clean[key] = sanitiseFilter(value, depth + 1);
  }

  return clean;
}

/**
 * Sanitise a projection object.
 * Only allows field names mapped to 0 or 1 (or true/false).
 */
function sanitiseProjection(obj) {
  if (obj === null || obj === undefined) {
    return undefined;
  }
  if (typeof obj !== 'object' || Array.isArray(obj)) {
    throw new Error('Projection must be a plain object');
  }

  const clean = {};
  for (const key of Object.keys(obj)) {
    if (key.startsWith('$')) {
      throw new Error('Projection fields must not start with $');
    }
    if (key.includes('\0')) {
      throw new Error('Projection field names must not contain null bytes');
    }
    const v = obj[key];
    if (v !== 0 && v !== 1 && v !== true && v !== false) {
      throw new Error(`Projection value for "${key}" must be 0, 1, true, or false`);
    }
    clean[key] = v;
  }
  return clean;
}

/**
 * Sanitise a sort specification.
 * Only allows field names mapped to 1 or -1.
 */
function sanitiseSort(obj) {
  if (obj === null || obj === undefined) {
    return undefined;
  }
  if (typeof obj !== 'object' || Array.isArray(obj)) {
    throw new Error('Sort must be a plain object');
  }

  const clean = {};
  for (const key of Object.keys(obj)) {
    if (key.startsWith('$')) {
      throw new Error('Sort fields must not start with $');
    }
    if (key.includes('\0')) {
      throw new Error('Sort field names must not contain null bytes');
    }
    const v = obj[key];
    if (v !== 1 && v !== -1) {
      throw new Error(`Sort value for "${key}" must be 1 or -1`);
    }
    clean[key] = v;
  }
  return clean;
}

// ---------------------------------------------------------------------------
// Query builder
// ---------------------------------------------------------------------------

const MAX_LIMIT = 200;
const DEFAULT_LIMIT = 50;

/**
 * Build and execute a safe MongoDB query.
 *
 * @param {import('mongodb').Collection} collection
 * @param {object} filter     – dynamic filter (will be sanitised)
 * @param {object} projection – field projection (will be sanitised)
 * @param {object} sort       – sort specification (will be sanitised)
 * @param {number} [limit]    – max documents to return
 * @param {number} [skip]     – documents to skip (pagination)
 * @returns {Promise<Array>}
 */
async function queryBuilder(collection, filter, projection, sort, limit, skip) {
  const safeFilter = sanitiseFilter(filter);
  const safeProjection = sanitiseProjection(projection);
  const safeSort = sanitiseSort(sort);

  const safeLimit = Math.min(
    Math.max(parseInt(limit, 10) || DEFAULT_LIMIT, 1),
    MAX_LIMIT,
  );
  const safeSkip = Math.max(parseInt(skip, 10) || 0, 0);

  let cursor = collection.find(safeFilter);

  if (safeProjection) {
    cursor = cursor.project(safeProjection);
  }
  if (safeSort) {
    cursor = cursor.sort(safeSort);
  }

  cursor = cursor.skip(safeSkip).limit(safeLimit);

  const results = await cursor.toArray();
  return results;
}

