let db;

async function connectDb() {
  const url = process.env.MONGO_URL || 'mongodb://localhost:27017';
  const client = new MongoClient(url);
  await client.connect();
  db = client.db(process.env.MONGO_DB || 'admin_dashboard');
  console.log('Connected to MongoDB');
  return client;
}

// Allowed collections that the admin dashboard can query
const ALLOWED_COLLECTIONS = new Set([
  'users',
  'orders',
  'products',
  'logs',
]);

/**
 * POST /api/query
 *
 * Body:
 * {
 *   "collection": "users",
 *   "filter": { "age": { "$gt": 18 }, "name": { "$regex": "^J" } },
 *   "projection": { "password": 0 },
 *   "sort": { "createdAt": -1 },
 *   "limit": 50,
 *   "skip": 0
 * }
 */
app.post('/api/query', async (req, res) => {
  try {
    const { collection: colName, filter, projection, sort, limit, skip } = req.body;

    if (!colName || typeof colName !== 'string') {
      return res.status(400).json({ error: 'collection is required' });
    }

    if (!ALLOWED_COLLECTIONS.has(colName)) {
      return res.status(400).json({ error: `Collection "${colName}" is not allowed` });
    }

    const collection = db.collection(colName);
    const results = await queryBuilder(collection, filter, projection, sort, limit, skip);

    return res.json({ count: results.length, data: results });
  } catch (err) {
    console.error('Query error:', err.message);
    return res.status(400).json({ error: err.message });
  }
});

// Health check
app.get('/health', (_req, res) => res.json({ status: 'ok' }));

